<?php
if (!defined('ABSPATH')) exit;
class VH360_Giving_Admin { private static $instance=null; const CAP='manage_options'; public static function get_instance(){ if(null===self::$instance) self::$instance=new self(); return self::$instance; } private function __construct(){ add_action('admin_menu',array($this,'menu'),20); add_action('admin_post_vh360_giving_save_settings',array($this,'save_settings')); add_action('admin_post_vh360_giving_save_fund',array($this,'save_fund')); add_action('admin_enqueue_scripts',array($this,'assets')); }
 public function menu(){ add_submenu_page('vh360-theme',__('Giving','videohub360-memberships'),__('Giving','videohub360-memberships'),self::CAP,'vh360-theme-giving',array($this,'render')); }
 public function assets($hook){ if(false!==strpos((string)$hook,'vh360-theme-giving')){ wp_enqueue_style('vh360-giving-admin',VH360_MEMBERSHIPS_URL.'assets/admin/giving-admin.css',array(),VH360_MEMBERSHIPS_VERSION); wp_enqueue_script('vh360-giving-admin',VH360_MEMBERSHIPS_URL.'assets/admin/giving-admin.js',array('jquery'),VH360_MEMBERSHIPS_VERSION,true); } }
 public function save_settings(){ if(!current_user_can(self::CAP)) wp_die('Forbidden'); check_admin_referer('vh360_giving_settings'); $o=vh360_giving_default_options(); foreach($o as $k=>$v){ $o[$k]=isset($_POST[$k])?sanitize_text_field(wp_unslash($_POST[$k])):0; } $o['enable_giving']=!empty($_POST['enable_giving'])?1:0; $o['enable_anonymous']=!empty($_POST['enable_anonymous'])?1:0; $o['enable_notes']=!empty($_POST['enable_notes'])?1:0; update_option('vh360_giving_options',$o); wp_safe_redirect(admin_url('admin.php?page=vh360-theme-giving&tab=settings&updated=1')); exit; }
 public function save_fund(){ if(!current_user_can(self::CAP)) wp_die('Forbidden'); check_admin_referer('vh360_giving_fund'); VH360_Giving_Funds::save_fund(wp_unslash($_POST)); wp_safe_redirect(admin_url('admin.php?page=vh360-theme-giving&tab=funds&updated=1')); exit; }
 public function render(){ $tab=isset($_GET['tab'])?sanitize_key(wp_unslash($_GET['tab'])):'overview'; echo '<div class="wrap vh360-giving-admin"><h1>'.esc_html__('VideoHub360 Giving','videohub360-memberships').'</h1><nav class="nav-tab-wrapper">'; foreach(array('overview'=>'Overview','settings'=>'Settings','funds'=>'Funds','transactions'=>'Transactions','reports'=>'Reports') as $k=>$l){ echo '<a class="nav-tab '.($tab===$k?'nav-tab-active':'').'" href="'.esc_url(admin_url('admin.php?page=vh360-theme-giving&tab='.$k)).'">'.esc_html__($l,'videohub360-memberships').'</a>'; } echo '</nav>'; if($tab==='settings') $this->settings(); elseif($tab==='funds') $this->funds(); elseif($tab==='transactions') $this->transactions(); elseif($tab==='reports') $this->reports(); else $this->overview(); echo '</div>'; }
 private function overview(){ $total=VH360_Giving_Transactions::total(); echo '<h2>Overview</h2><div class="vh360-giving-cards"><div class="card"><h3>Total Giving</h3><p class="big">'.esc_html(vh360_giving_format_amount($total)).'</p></div><div class="card"><h3>Status</h3><p>'.(vh360_giving_is_enabled()?'Enabled':'Disabled').'</p></div></div>'; $this->reports(); }
 private function settings(){ $o=vh360_giving_options(); echo '<form method="post" action="'.esc_url(admin_url('admin-post.php')).'"><input type="hidden" name="action" value="vh360_giving_save_settings">'; wp_nonce_field('vh360_giving_settings'); echo '<table class="form-table">'; $fields=array('dashboard_tab_label'=>'Frontend dashboard tab label','default_currency'=>'Default currency','minimum_amount'=>'Minimum giving amount','suggested_amounts'=>'Suggested amounts','success_message'=>'Success message','cancel_message'=>'Cancel message'); echo '<tr><th>Enable Giving</th><td><label><input type="checkbox" name="enable_giving" value="1" '.checked($o['enable_giving'],1,false).'> Enable Giving</label></td></tr>'; foreach($fields as $k=>$l){ echo '<tr><th>'.esc_html($l).'</th><td><input class="regular-text" name="'.esc_attr($k).'" value="'.esc_attr($o[$k]).'"></td></tr>'; } echo '<tr><th>Options</th><td><label><input type="checkbox" name="enable_anonymous" value="1" '.checked($o['enable_anonymous'],1,false).'> Anonymous giving</label><br><label><input type="checkbox" name="enable_notes" value="1" '.checked($o['enable_notes'],1,false).'> Donor notes</label></td></tr></table>'; submit_button('Save Giving Settings'); echo '</form>'; }
 private function funds(){ $funds=VH360_Giving_Funds::get_funds(false); echo '<h2>Funds</h2><table class="widefat striped"><thead><tr><th>Order</th><th>Label</th><th>Key</th><th>Suggested</th><th>Enabled</th></tr></thead><tbody>'; foreach($funds as $f){ echo '<tr><td>'.esc_html($f->display_order).'</td><td>'.esc_html($f->label).'</td><td><code>'.esc_html($f->fund_key).'</code></td><td>'.esc_html($f->suggested_amounts).'</td><td>'.($f->enabled?'Yes':'No').'</td></tr>'; } echo '</tbody></table><h3>Add / Update Fund</h3><form method="post" action="'.esc_url(admin_url('admin-post.php')).'"><input type="hidden" name="action" value="vh360_giving_save_fund">'; wp_nonce_field('vh360_giving_fund'); echo '<table class="form-table"><tr><th>ID to update</th><td><input name="id" type="number"></td></tr><tr><th>Label</th><td><input name="label" required></td></tr><tr><th>Fund key</th><td><input name="fund_key"></td></tr><tr><th>Description</th><td><textarea name="description"></textarea></td></tr><tr><th>Suggested amounts</th><td><input name="suggested_amounts" value="10,25,50,100"></td></tr><tr><th>Default amount</th><td><input name="default_amount" type="number" step="0.01"></td></tr><tr><th>Order</th><td><input name="display_order" type="number" value="0"></td></tr><tr><th>Enabled</th><td><input name="enabled" type="checkbox" value="1" checked></td></tr></table>'; submit_button('Save Fund'); echo '</form>'; }
 private function transactions(){ global $wpdb; $t=VH360_Giving_Database::get_transactions_table(); $rows=$wpdb->get_results("SELECT * FROM {$t} ORDER BY created_at DESC LIMIT 100"); echo '<h2>Transactions</h2><p>Filter by status, fund, date range, and member search can be added above this source-aware transaction log.</p><table class="widefat striped"><thead><tr><th>Donor</th><th>Amount</th><th>Fund</th><th>Status</th><th>Gateway</th><th>Source</th><th>Date</th><th>Stripe IDs</th></tr></thead><tbody>'; foreach($rows as $r){ $u=get_userdata($r->user_id); echo '<tr><td>'.esc_html($u?$u->display_name:'#'.$r->user_id).'</td><td>'.esc_html(vh360_giving_format_amount($r->amount,$r->currency)).'</td><td>'.esc_html($r->fund_label).'</td><td>'.esc_html($r->status).'</td><td>'.esc_html($r->gateway).'</td><td>'.esc_html($r->source).'</td><td>'.esc_html($r->created_at).'</td><td><code>'.esc_html($r->stripe_checkout_session_id).' '.esc_html($r->stripe_payment_intent_id).'</code></td></tr>'; } echo '</tbody></table>'; }
 private function reports(){ global $wpdb; $t=VH360_Giving_Database::get_transactions_table(); echo '<h2>Reports</h2><p>Total this year: '.esc_html(vh360_giving_format_amount(VH360_Giving_Transactions::total("YEAR(given_at)=YEAR(CURDATE())"))).' | Total this month: '.esc_html(vh360_giving_format_amount(VH360_Giving_Transactions::total("YEAR(given_at)=YEAR(CURDATE()) AND MONTH(given_at)=MONTH(CURDATE())"))).'</p>'; $rows=$wpdb->get_results("SELECT fund_label,SUM(amount) total FROM {$t} WHERE status='paid' GROUP BY fund_label ORDER BY total DESC"); echo '<table class="widefat striped"><thead><tr><th>Fund</th><th>Total</th></tr></thead><tbody>'; foreach($rows as $r) echo '<tr><td>'.esc_html($r->fund_label).'</td><td>'.esc_html(vh360_giving_format_amount($r->total)).'</td></tr>'; echo '</tbody></table>'; }
}
